&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;​&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/23/05/F1_State%20Govt_Arbaz_23-05-2023_Yuvraj_D2.png&quot; style=&quot;width: 258px; height: 142px;&quot; /&gt;&lt;/p&gt;

